#!/usr/bin/env node

import fs from 'node:fs';
import path from 'node:path';
import { performance } from 'node:perf_hooks';

type Format = 'gg' | 'json' | 'plain';

interface FileRecord {
  id: string;
  path: string;
  bytes: number;
  kind: 'file' | 'directory' | 'symlink' | 'other';
  elapsedUs: number;
}

interface SearchHit {
  id: string;
  fileId: string;
  path: string;
  line: number;
  column: number;
  text: string;
  elapsedUs: number;
}

interface Topology {
  command: string;
  argv: string[];
  cwd: string;
  startedAt: string;
  completedAt: string;
  elapsedUs: number;
  files: FileRecord[];
  hits: SearchHit[];
  output: string[];
}

function usage(): never {
  console.log(`rip — sovereign filesystem/search/text adapter

Usage:
  rip find [root] [--plain|--json|--gg]
  rip ls [root] [--plain|--json|--gg]
  rip which <command> [--plain|--json|--gg]
  rip grep <pattern> [root] [--plain|--json|--gg]
  rip rg <pattern> [root] [--plain|--json|--gg]
  rip cat|head|tail|wc|stat|file <path> [--plain|--json|--gg]
  rip xargs [--plain|--json|--gg]
`);
  process.exit(1);
}

function parseFormat(args: string[]): { format: Format; args: string[]; explicit: boolean } {
  let format: Format = 'gg';
  let explicit = false;
  const filtered: string[] = [];
  for (const arg of args) {
    if (arg === '--plain') {
      format = 'plain';
      explicit = true;
    } else if (arg === '--json') {
      format = 'json';
      explicit = true;
    } else if (arg === '--gg') {
      format = 'gg';
      explicit = true;
    }
    else filtered.push(arg);
  }
  return { format, args: filtered, explicit };
}

function esc(value: string): string {
  return value.replace(/\\/g, '\\\\').replace(/'/g, "\\'").replace(/\n/g, '\\n');
}

function idFor(prefix: string, value: string, index: number): string {
  const clean = value.replace(/[^a-zA-Z0-9]+/g, '_').replace(/^_+|_+$/g, '').slice(0, 48);
  return `${prefix}_${index}_${clean || 'node'}`;
}

function fileKind(stat: fs.Stats): FileRecord['kind'] {
  if (stat.isFile()) return 'file';
  if (stat.isDirectory()) return 'directory';
  if (stat.isSymbolicLink()) return 'symlink';
  return 'other';
}

function recordPath(target: string, index: number): FileRecord {
  const started = performance.now();
  const stat = fs.lstatSync(target);
  return {
    id: idFor('file', target, index),
    path: target,
    bytes: stat.size,
    kind: fileKind(stat),
    elapsedUs: Math.round((performance.now() - started) * 1000),
  };
}

function walk(root: string, limit = 4096): FileRecord[] {
  const abs = path.resolve(root);
  const records: FileRecord[] = [];
  const stack = [abs];
  while (stack.length > 0 && records.length < limit) {
    const current = stack.pop()!;
    const record = recordPath(current, records.length);
    records.push(record);
    if (record.kind === 'directory') {
      const started = performance.now();
      const entries = fs.readdirSync(current).sort();
      record.elapsedUs += Math.round((performance.now() - started) * 1000);
      for (let i = entries.length - 1; i >= 0; i--) {
        const entry = entries[i];
        if (entry) stack.push(path.join(current, entry));
      }
    }
  }
  return records;
}

function readText(file: string): string {
  return fs.readFileSync(file, 'utf8');
}

function search(pattern: string, root: string): { files: FileRecord[]; hits: SearchHit[]; output: string[] } {
  const matcher = new RegExp(pattern, 'i');
  const files = walk(root);
  const hits: SearchHit[] = [];
  const output: string[] = [];
  for (const file of files) {
    if (file.kind !== 'file' || file.bytes > 2_000_000) continue;
    const started = performance.now();
    let text = '';
    try {
      text = readText(file.path);
    } catch {
      continue;
    }
    const lines = text.split(/\r?\n/);
    for (let i = 0; i < lines.length; i++) {
      const line = lines[i]!;
      const match = matcher.exec(line);
      if (!match) continue;
      const hit = {
        id: idFor('hit', `${file.path}_${i}`, hits.length),
        fileId: file.id,
        path: file.path,
        line: i + 1,
        column: match.index + 1,
        text: line,
        elapsedUs: Math.round((performance.now() - started) * 1000),
      };
      hits.push(hit);
      output.push(`${file.path}:${hit.line}:${hit.column}:${line}`);
    }
  }
  return { files, hits, output };
}

function renderGG(topology: Topology): string {
  const lines = [
    `(rip: RipCommand { command: '${esc(topology.command)}', cwd: '${esc(topology.cwd)}', elapsed_us: ${topology.elapsedUs}, files: ${topology.files.length}, hits: ${topology.hits.length} })`,
  ];
  for (const file of topology.files) {
    lines.push(`(${file.id}: File { path: '${esc(file.path)}', kind: '${file.kind}', bytes: ${file.bytes}, stat_us: ${file.elapsedUs} })`);
    lines.push(`(rip)-[:TOUCH { stat_us: ${file.elapsedUs} }]->(${file.id})`);
  }
  for (const hit of topology.hits) {
    lines.push(`(${hit.id}: Match { path: '${esc(hit.path)}', line: ${hit.line}, column: ${hit.column}, elapsed_us: ${hit.elapsedUs}, text: '${esc(hit.text)}' })`);
    lines.push(`(${hit.fileId})-[:YIELDS]->(${hit.id})`);
    lines.push(`(${hit.id})-[:FOLD]->(rip)`);
  }
  if (topology.output.length > 0) {
    lines.push(`(stdout: Output { lines: ${topology.output.length} })`);
    lines.push('(rip)-[:EMIT]->(stdout)');
  }
  return `${lines.join('\n')}\n`;
}

function emit(topology: Topology, format: Format) {
  if (format === 'json') {
    console.log(JSON.stringify(topology, null, 2));
  } else if (format === 'plain') {
    console.log(topology.output.join('\n'));
  } else {
    process.stdout.write(renderGG(topology));
  }
}

async function main() {
  const parsed = parseFormat(process.argv.slice(2));
  const [command, ...args] = parsed.args;
  if (!command) usage();

  const started = performance.now();
  const startedAt = new Date().toISOString();
  let files: FileRecord[] = [];
  let hits: SearchHit[] = [];
  let output: string[] = [];

  if (command === 'find') {
    files = walk(args[0] ?? '.');
    output = files.map((file) => file.path);
  } else if (command === 'ls') {
    const root = path.resolve(args[0] ?? '.');
    const entries = fs.readdirSync(root).sort().map((entry, index) => {
      const full = path.join(root, entry);
      const record = recordPath(full, index);
      files.push(record);
      return entry;
    });
    output = entries;
  } else if (command === 'which') {
    const needle = args[0];
    if (!needle) usage();
    const pathParts = (process.env.PATH ?? '').split(path.delimiter).filter(Boolean);
    const found = pathParts.find((dir) => {
      const candidate = path.join(dir, needle);
      try {
        fs.accessSync(candidate, fs.constants.X_OK);
        return true;
      } catch {
        return false;
      }
    });
    output = found ? [path.join(found, needle)] : [];
    if (found) files = [recordPath(path.join(found, needle), 0)];
  } else if (command === 'grep' || command === 'rg') {
    if (!args[0]) usage();
    ({ files, hits, output } = search(args[0], args[1] ?? '.'));
  } else if (['cat', 'less', 'head', 'tail', 'wc', 'stat', 'file'].includes(command)) {
    const wcFlags = command === 'wc' ? args.filter((arg) => arg.startsWith('-')) : [];
    const target = command === 'wc' ? args.find((arg) => !arg.startsWith('-')) : args[0];
    if (command === 'wc' && !parsed.explicit) {
      parsed.format = 'plain';
    }
    if (command === 'wc' && !target) {
      const text = fs.readFileSync(0, 'utf8');
      const bytes = Buffer.byteLength(text);
      const lines = text.length === 0 ? 0 : text.split(/\n/).length - (text.endsWith('\n') ? 0 : 1);
      const words = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;
      if (wcFlags.includes('-c')) output = [`${bytes}`];
      else if (wcFlags.includes('-l')) output = [`${lines}`];
      else if (wcFlags.includes('-w')) output = [`${words}`];
      else output = [`${lines} ${words} ${bytes}`];
      emit(
        {
          command,
          argv: args,
          cwd: process.cwd(),
          startedAt,
          completedAt: new Date().toISOString(),
          elapsedUs: Math.round((performance.now() - started) * 1000),
          files,
          hits,
          output,
        },
        parsed.format,
      );
      return;
    }
    if (!target) usage();
    const abs = path.resolve(target);
    files = [recordPath(abs, 0)];
    if (command === 'stat') {
      const stat = fs.statSync(abs);
      output = [`${abs} ${stat.size} ${stat.mode.toString(8)} ${stat.mtime.toISOString()}`];
    } else if (command === 'file') {
      output = [`${abs}: ${files[0]!.kind}, ${files[0]!.bytes} bytes`];
    } else if (command === 'wc') {
      const text = readText(abs);
      const lines = text.length === 0 ? 0 : text.split(/\n/).length - (text.endsWith('\n') ? 0 : 1);
      const words = text.trim() === '' ? 0 : text.trim().split(/\s+/).length;
      const bytes = Buffer.byteLength(text);
      if (wcFlags.includes('-c')) output = [`${bytes} ${target}`];
      else if (wcFlags.includes('-l')) output = [`${lines} ${target}`];
      else if (wcFlags.includes('-w')) output = [`${words} ${target}`];
      else output = [`${lines} ${words} ${bytes} ${target}`];
    } else {
      const lines = readText(abs).split(/\r?\n/);
      const selected = command === 'head' ? lines.slice(0, 10) : command === 'tail' ? lines.slice(-10) : lines;
      output = selected;
    }
  } else if (command === 'xargs') {
    const stdin = fs.readFileSync(0, 'utf8');
    output = stdin.split(/\s+/).filter(Boolean);
  } else {
    usage();
  }

  emit(
    {
      command,
      argv: args,
      cwd: process.cwd(),
      startedAt,
      completedAt: new Date().toISOString(),
      elapsedUs: Math.round((performance.now() - started) * 1000),
      files,
      hits,
      output,
    },
    parsed.format,
  );
}

main().catch((error: unknown) => {
  const message = error instanceof Error ? error.message : String(error);
  console.error(`rip: ${message}`);
  process.exit(1);
});
